const _ = require("lodash");
const data = require("../../data/problems.json");

/**
 * Normalize tags to lowercase trimmed strings.
 * @param {string|string[]} tags
 * @returns {string[]}
 */
function normalizeTags(tags) {
  if (!tags) return [];
  if (Array.isArray(tags)) {
    return tags.map(t => t.toLowerCase().trim()).filter(t => t);
  }
  // comma separated string
  return tags.split(",").map(t => t.toLowerCase().trim()).filter(t => t);
}

/**
 * Get problems filtered by difficulty, limit, and skill tags.
 * @param {Object} params
 * @param {string|string[]} [params.skillTags] - skill tags filter (case-insensitive, comma separated or array)
 * @param {string} [params.difficulty] - difficulty filter (exact match)
 * @param {number} [params.limit] - max number of problems to return
 * @returns {Object} result with problems array and metadata
 */
function getProblems({ skillTags, difficulty, limit } = {}) {
  const normalizedTags = normalizeTags(skillTags);

  // Filter problems by difficulty if provided
  let filtered = data;
  if (difficulty) {
    filtered = filtered.filter(p => p.difficulty === difficulty);
  }

  // Filter by skill tags if provided
  if (normalizedTags.length > 0) {
    filtered = filtered.filter(p => {
      if (!p.tags || !Array.isArray(p.tags)) return false;
      // normalize problem tags
      const problemTags = p.tags.map(t => t.toLowerCase().trim());
      // check if problemTags contain all normalizedTags
      return normalizedTags.every(t => problemTags.includes(t));
    });
  }

  // Sort by stable criteria: difficulty asc, then id asc
  filtered = _.orderBy(filtered, ["difficulty", "id"], ["asc", "asc"]);

  // Apply limit if provided
  if (limit && Number.isInteger(limit) && limit > 0) {
    filtered = filtered.slice(0, limit);
  }

  // Compose metadata
  const metadata = {
    total: filtered.length,
    filters: {
      difficulty: difficulty || null,
      skillTags: normalizedTags.length > 0 ? normalizedTags : null,
      limit: limit || null
    }
  };

  return { problems: filtered, metadata };
}

module.exports = {
  getProblems
};
